/**
 * Tests for Auth Service
 */

import AsyncStorage from "@react-native-async-storage/async-storage";
import * as SecureStore from "expo-secure-store";
import {
  login,
  logout,
  register,
  refreshToken,
  validateToken,
  sendOTP,
  verifyOTP,
} from "../../services/authService";
import { apiFetch } from "../../services/api";

// Mock dependencies
jest.mock("@react-native-async-storage/async-storage", () => ({
  getItem: jest.fn(),
  setItem: jest.fn(),
  removeItem: jest.fn(),
  multiRemove: jest.fn(),
}));

jest.mock("expo-secure-store", () => ({
  getItemAsync: jest.fn(),
  setItemAsync: jest.fn(),
  deleteItemAsync: jest.fn(),
}));

jest.mock("../../services/api", () => ({
  apiFetch: jest.fn(),
  setAuthToken: jest.fn(),
  clearAuthToken: jest.fn(),
}));

describe("authService", () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe("login", () => {
    it("should login with email and password", async () => {
      const mockResponse = {
        user: { id: "user-1", email: "test@test.com", name: "Test User" },
        accessToken: "access-token-123",
        refreshToken: "refresh-token-456",
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockResponse);

      const result = await login({
        email: "test@test.com",
        password: "password123",
      });

      expect(apiFetch).toHaveBeenCalledWith("/auth/login", {
        method: "POST",
        body: { email: "test@test.com", password: "password123" },
      });
      expect(result.user.email).toBe("test@test.com");
    });

    it("should login with phone number", async () => {
      const mockResponse = {
        user: { id: "user-1", phone: "0901234567" },
        accessToken: "access-token-123",
        refreshToken: "refresh-token-456",
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockResponse);

      const result = await login({
        phone: "0901234567",
        otp: "123456",
      });

      expect(apiFetch).toHaveBeenCalledWith("/auth/login", {
        method: "POST",
        body: expect.objectContaining({ phone: "0901234567" }),
      });
    });
  });

  describe("logout", () => {
    it("should clear all auth data", async () => {
      await logout();

      expect(SecureStore.deleteItemAsync).toHaveBeenCalledWith("accessToken");
      expect(SecureStore.deleteItemAsync).toHaveBeenCalledWith("refreshToken");
    });
  });

  describe("register", () => {
    it("should register a new user", async () => {
      const mockResponse = {
        user: { id: "user-new", email: "new@test.com" },
        message: "Registration successful",
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockResponse);

      const result = await register({
        email: "new@test.com",
        password: "password123",
        name: "New User",
        phone: "0901234567",
      });

      expect(apiFetch).toHaveBeenCalledWith("/auth/register", {
        method: "POST",
        body: expect.objectContaining({
          email: "new@test.com",
          name: "New User",
        }),
      });
    });
  });

  describe("refreshToken", () => {
    it("should refresh the access token", async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue(
        "refresh-token-456",
      );
      (apiFetch as jest.Mock).mockResolvedValue({
        accessToken: "new-access-token",
        refreshToken: "new-refresh-token",
      });

      const result = await refreshToken();

      expect(apiFetch).toHaveBeenCalledWith("/auth/refresh", {
        method: "POST",
        body: { refreshToken: "refresh-token-456" },
      });
    });

    it("should throw if no refresh token", async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue(null);

      await expect(refreshToken()).rejects.toThrow();
    });
  });

  describe("validateToken", () => {
    it("should validate a token", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({ valid: true });

      const result = await validateToken("token-123");

      expect(apiFetch).toHaveBeenCalledWith("/auth/validate", {
        method: "POST",
        body: { token: "token-123" },
      });
      expect(result.valid).toBe(true);
    });
  });

  describe("sendOTP", () => {
    it("should send OTP to phone number", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({
        success: true,
        message: "OTP sent",
      });

      const result = await sendOTP("0901234567");

      expect(apiFetch).toHaveBeenCalledWith("/auth/otp/send", {
        method: "POST",
        body: { phone: "0901234567" },
      });
      expect(result.success).toBe(true);
    });
  });

  describe("verifyOTP", () => {
    it("should verify OTP code", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({
        valid: true,
        user: { id: "user-1" },
        accessToken: "token-123",
      });

      const result = await verifyOTP("0901234567", "123456");

      expect(apiFetch).toHaveBeenCalledWith("/auth/otp/verify", {
        method: "POST",
        body: { phone: "0901234567", code: "123456" },
      });
      expect(result.valid).toBe(true);
    });

    it("should reject invalid OTP", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({
        valid: false,
        message: "Invalid OTP",
      });

      const result = await verifyOTP("0901234567", "000000");

      expect(result.valid).toBe(false);
    });
  });
});
